export const 摧魔玉符 = (bi) => {
    const u = bi.u, k = 2.25;
    const X = (c) => (c - 5.0) * k;
    const Z = (r) => (r - 0.1) * k + 0.8;
    const 抖 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 摺 = (x0, x1, rT, rB, n, 左起 = true, 寬 = 0.4) => 抖(pa => {
        const p = n > 1 ? (rB - rT) / (n - 1) : 0;
        let dir = 左起 ? 1 : -1, y = rT;
        pa.M(X(dir > 0 ? x0 : x1), Z(y));
        for (let i = 0; i < n; i++) {
            const xe = dir > 0 ? x1 : x0;
            if (i < n - 1) {
                pa.L(X(xe - dir * p * 0.35), Z(y));
                pa.C(X(xe + dir * p * 1.05), Z(y - p * 0.05), X(xe + dir * p * 1.05), Z(y + p * 1.05), X(xe - dir * p * 0.35), Z(y + p));
                y += p;
                dir = -dir;
            }
            else
                pa.L(X(xe), Z(y));
        }
    }, 寬);
    // 頭三疊帶（左厂臂）
    摺(0.4, 3.2, 0.15, 3.4, 6);
    抖(p => p.M(X(0.5), Z(1.15)).C(X(0.3), Z(2.0), X(0.3), Z(3.0), X(0.5), Z(3.6)), 0.4);
    摺(3.9, 6.3, 0.1, 3.5, 7);
    摺(6.9, 9.6, 0.4, 3.0, 5);
    // 桁帶（厂臂・左小環・右端鉤）
    抖(p => p.M(X(0.5), Z(3.85)).C(X(0.3), Z(4.3), X(0.3), Z(4.9), X(0.5), Z(5.2)), 0.4);
    抖(p => p.M(X(0.9), Z(4.35))
        .C(X(1.5), Z(4.22), X(1.55), Z(4.6), X(1.0), Z(4.62)), 0.4);
    線(p => p.M(X(1.1), Z(4.28)).L(X(9.3), Z(4.2)), 0.4);
    抖(p => p.M(X(0.7), Z(5.15)).L(X(9.35), Z(5.08))
        .C(X(9.7), Z(5.2), X(9.65), Z(5.6), X(9.4), Z(5.75)), 0.4);
    // 立目帶三具（窄摺直梯；中具貫莖・右具綴右豎）
    摺(1.0, 2.9, 5.95, 9.4, 7);
    摺(3.8, 5.9, 5.55, 9.35, 7);
    線(p => p.M(X(4.85), Z(5.6)).L(X(4.83), Z(9.3)), 0.34);
    摺(6.5, 8.4, 5.55, 9.5, 7);
    線(p => p.M(X(9.35), Z(5.5)).L(X(9.33), Z(9.5)), 0.4);
    // 滿幅桁
    線(p => p.M(X(0.7), Z(9.8)).L(X(9.6), Z(9.72)), 0.4);
    // 大匚抱帶：頂摺右迴＋匚臂＋內梯二＋墜摺＋內底桁＋左緣點
    抖(p => p.M(X(1.6), Z(10.15)).L(X(8.2), Z(10.08))
        .C(X(9.7), Z(10.12), X(9.7), Z(11.5), X(8.2), Z(11.55))
        .L(X(1.7), Z(11.62)), 0.42);
    抖(p => p.M(X(0.75), Z(11.75))
        .C(X(0.42), Z(12.6), X(0.4), Z(16.2), X(0.75), Z(17.1))
        .C(X(0.85), Z(17.35), X(1.1), Z(17.5), X(1.4), Z(17.55)), 0.42);
    摺(1.5, 4.4, 11.95, 16.9, 6);
    線(p => p.M(X(2.45), Z(12.2)).L(X(2.43), Z(16.6)), 0.3);
    摺(5.8, 8.2, 11.95, 14.9, 4);
    摺(7.9, 9.5, 15.05, 17.4, 3);
    線(p => p.M(X(1.6), Z(17.15)).L(X(6.5), Z(17.1)), 0.38);
    抖(p => p.M(X(0.68), Z(17.6)).C(X(0.9), Z(17.55), X(0.95), Z(17.75), X(0.75), Z(17.8)), 0.38);
    // 底疊帶：雙桁（下桁波曳）＋三疊＋滿幅桁＋末三疊（厂臂尾曳）
    抖(p => p.M(X(0.5), Z(17.95)).L(X(9.4), Z(17.88))
        .C(X(9.75), Z(18.0), X(9.7), Z(18.6), X(9.45), Z(18.75)), 0.4);
    抖(p => p.M(X(0.6), Z(19.3))
        .C(X(2.0), Z(19.1), X(4.0), Z(19.5), X(6.0), Z(19.2))
        .C(X(7.5), Z(19.02), X(8.5), Z(19.4), X(9.6), Z(19.25)), 0.4);
    摺(0.4, 3.3, 19.6, 23.2, 5);
    摺(3.8, 6.4, 19.5, 24.3, 6);
    摺(6.8, 9.6, 19.5, 23.3, 5);
    線(p => p.M(X(0.6), Z(23.6)).L(X(9.5), Z(23.52)), 0.4);
    摺(0.6, 3.2, 24.4, 26.7, 3);
    抖(p => p.M(X(0.38), Z(24.5)).C(X(0.2), Z(25.3), X(0.25), Z(26.0), X(0.45), Z(26.5)), 0.4);
    摺(3.7, 6.3, 24.5, 26.8, 3);
    摺(6.7, 9.4, 24.4, 26.6, 3);
    抖(p => p.M(X(9.45), Z(26.0)).C(X(9.62), Z(26.4), X(9.5), Z(26.7), X(9.2), Z(26.78)), 0.38);
};
